import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Profile.css';

function Profile() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [userData, setUserData] = useState({
    email: '',
    name: '',
    age: '',
    sex: '',
    smoking: '',
    allergy: ''
  });
  const [originalData, setOriginalData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [userRole, setUserRole] = useState('user');
  const [isViewingAsUser, setIsViewingAsUser] = useState(false);

  // Ефект для очищення класу body при розмонтуванні компонента
  useEffect(() => {
    return () => {
      document.body.classList.remove('sidebar-open');
      document.documentElement.classList.remove('sidebar-open');
    };
  }, []);

  useEffect(() => {
    // Перевіряємо, чи переглядаємо як інший користувач
    const viewing_as_user_id = localStorage.getItem('viewing_as_user_id');
    const user_id = viewing_as_user_id || localStorage.getItem('user_id');
    setIsViewingAsUser(!!viewing_as_user_id);

    if (!user_id) {
      navigate('/');
      return;
    }

    const fetchUserData = async () => {
      setIsLoading(true);
      setError('');

      try {
        // Спочатку перевіримо роль користувача, щоб очистити viewing_as_user_id, якщо потрібно
        const roleResponse = await fetch(`http://localhost:5000/api/user-role/${localStorage.getItem('user_id')}`);
        if (roleResponse.ok) {
          const roleData = await roleResponse.json();
          const userRole = roleData.role || 'user';

          // Якщо користувач не адмін, але є viewing_as_user_id, очищаємо його
          if (userRole !== 'admin' && viewing_as_user_id) {
            localStorage.removeItem('viewing_as_user_id');
            localStorage.removeItem('selected_user_id');
            // Перезавантажуємо сторінку, щоб оновити стан
            window.location.reload();
            return;
          }
        }

        // Перевіряємо, чи переглядаємо як інший користувач після перевірки ролі
        const current_viewing_as_user_id = localStorage.getItem('viewing_as_user_id');
        const current_user_id = current_viewing_as_user_id || localStorage.getItem('user_id');

        if (!current_user_id) {
          navigate('/');
          return;
        }

        // Fetch user data
        const response = await fetch(`http://localhost:5000/api/user-data/${current_user_id}`);
        const data = await response.json();

        if (response.ok) {
          // Fetch email from users table
          const emailResponse = await fetch(`http://localhost:5000/api/user-email/${current_user_id}`);
          const emailData = await emailResponse.json();

          if (emailResponse.ok) {
            const completeData = {
              ...data,
              email: emailData.email,
              smoking: data.smoking === 1 ? 'yes' : 'no', // Convert smoking value to yes/no
              sex: data.sex // Keep the sex value as is from the database
            };
            setUserData(completeData);
            setOriginalData(completeData);
          } else {
            throw new Error(emailData.error);
          }
        } else {
          throw new Error(data.error);
        }
      } catch (error) {
        console.error('Error fetching user data:', error);
        setError('Failed to load user data');
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
    checkUserRole();
  }, [navigate]);

  // Ефект для відстеження зміни стану sidebar і оновлення класу body
  useEffect(() => {
    if (isSidebarOpen) {
      document.body.classList.add('sidebar-open');
      document.documentElement.classList.add('sidebar-open');
    } else {
      document.body.classList.remove('sidebar-open');
      document.documentElement.classList.remove('sidebar-open');
    }
  }, [isSidebarOpen]);

  // Check user role
  const checkUserRole = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/user-role/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to verify user role');
      }

      const data = await response.json();
      setUserRole(data.role || 'user');
    } catch (error) {
      console.error('Error checking user role:', error);
      setUserRole('user');
    }
  };

  const handleChange = (e) => {
    // Якщо переглядаємо як інший користувач, не дозволяємо зміни
    if (isViewingAsUser) return;

    const { name, value } = e.target;
    setUserData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Не дозволяємо відправку форми, якщо переглядаємо як інший користувач
    if (isViewingAsUser) {
      return;
    }

    setError('');
    setSuccess('');

    try {
      // Перевіряємо, чи переглядаємо як інший користувач
      const viewing_as_user_id = localStorage.getItem('viewing_as_user_id');
      const user_id = viewing_as_user_id || localStorage.getItem('user_id');

      if (!user_id) {
        navigate('/');
        return;
      }

      // Update user data
      const response = await fetch(`http://localhost:5000/api/update-user-data/${user_id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          name: userData.name,
          age: userData.age,
          sex: userData.sex,
          smoking: userData.smoking === 'yes' ? 1 : 0,
          allergy: userData.allergy
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to update user data');
      }

      // Update email if changed
      if (userData.email !== originalData.email) {
        const emailResponse = await fetch(`http://localhost:5000/api/update-email/${user_id}`, {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ email: userData.email }),
        });

        if (!emailResponse.ok) {
          throw new Error('Failed to update email');
        }
      }

      setSuccess('Changes saved successfully');
      setOriginalData(userData);
    } catch (error) {
      console.error('Error updating user data:', error);
      setError('Failed to save changes');
    }
  };

  const hasChanges = () => {
    if (!originalData) return false;
    return Object.keys(userData).some(key => userData[key] !== originalData[key]);
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    localStorage.removeItem('viewing_as_user_id');
    localStorage.removeItem('selected_user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
    // Додавання/видалення класу до body для блокування прокрутки і правильного відображення сайдбару
    if (!isSidebarOpen) {
      document.body.classList.add('sidebar-open');
      document.documentElement.classList.add('sidebar-open');
    } else {
      document.body.classList.remove('sidebar-open');
      document.documentElement.classList.remove('sidebar-open');
    }
  };

  // Функція для закриття сайдбара при кліку на фон
  const closeSidebar = () => {
    if (isSidebarOpen) {
      setIsSidebarOpen(false);
      document.body.classList.remove('sidebar-open');
      document.documentElement.classList.remove('sidebar-open');
    }
  };

  const handleHome = () => {
    const viewing_as_user_id = localStorage.getItem('viewing_as_user_id');

    // Якщо переглядаємо як інший користувач, повертаємося на адмін-панель
    if (viewing_as_user_id) {
      localStorage.removeItem('viewing_as_user_id');
      navigate('/admin-dashboard');
    } else if (userRole === 'admin') {
      navigate('/admin-dashboard');
    } else {
      navigate('/dashboard');
    }
  };

  if (isLoading) {
    return <div className="profile-container">Loading...</div>;
  }

  return (
    <div className={`profile-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <button 
          className="menu-toggle-btn" 
          onClick={toggleSidebar}
          aria-label="Toggle menu"
        >
          <span></span>
          <span></span>
          <span></span>
        </button>
        <div className="top-center">
          <h1>Profile Settings</h1>
        </div>

        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="profile-content">
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}
        <form onSubmit={handleSubmit} className="profile-form">
          <div className="profile-form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={userData.email}
              onChange={handleChange}
              required
              disabled={isViewingAsUser}
              className={isViewingAsUser ? 'view-only' : ''}
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="name">Name</label>
            <input
              type="text"
              id="name"
              name="name"
              value={userData.name}
              onChange={handleChange}
              required
              disabled={isViewingAsUser}
              className={isViewingAsUser ? 'view-only' : ''}
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="age">Age</label>
            <input
              type="number"
              id="age"
              name="age"
              value={userData.age}
              onChange={handleChange}
              required
              min="1"
              disabled={isViewingAsUser}
              className={isViewingAsUser ? 'view-only' : ''}
            />
          </div>
          <div className="profile-form-group">
            <label htmlFor="sex">Gender</label>
            <select
              id="sex"
              name="sex"
              value={userData.sex}
              onChange={handleChange}
              required
              disabled={isViewingAsUser}
              className={isViewingAsUser ? 'view-only' : ''}
            >
              <option value="">Select Gender</option>
              <option value="male">Male</option>
              <option value="female">Female</option>
            </select>
          </div>
          <div className="profile-form-group">
            <label className="radio-label">Smoking Status</label>
            <div className="radio-group">
              <label className={isViewingAsUser ? 'view-only' : ''}>
                <input
                  type="radio"
                  name="smoking"
                  value="yes"
                  checked={userData.smoking === 'yes'}
                  onChange={handleChange}
                  required
                  disabled={isViewingAsUser}
                />
                Yes
              </label>
              <label className={isViewingAsUser ? 'view-only' : ''}>
                <input
                  type="radio"
                  name="smoking"
                  value="no"
                  checked={userData.smoking === 'no'}
                  onChange={handleChange}
                  disabled={isViewingAsUser}
                />
                No
              </label>
            </div>
          </div>
          <div className="profile-form-group">
            <label htmlFor="allergy">Allergies</label>
            <input
              type="text"
              id="allergy"
              name="allergy"
              value={userData.allergy}
              onChange={handleChange}
              required
              disabled={isViewingAsUser}
              className={isViewingAsUser ? 'view-only' : ''}
            />
            <div className="allergies-hint">
              Please list your allergies separated by commas. Common allergies: pollen, dust, mold, pets, food. Write "none" if you don't have any allergies.
            </div>
          </div>
          {!isViewingAsUser && (
            <button 
              type="submit" 
              className="save-button"
              disabled={!hasChanges() || isViewingAsUser}
            >
              Save Changes
            </button>
          )}
        </form>
      </div>


      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
         <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={handleHome}>
            <span className="menu-icon">🏠</span> Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            <span className="menu-icon">📊</span> Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            <span className="menu-icon">🔮</span> Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            <span className="menu-icon">📈</span> Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            <span className="menu-icon">💊</span> Medication Diary
          </button>
        </nav>
      </div>

      {/* Backdrop for mobile */}
      <div className="sidebar-backdrop" onClick={closeSidebar}></div>
    </div>

  );

}

export default Profile;
